  --url http://localhost:9200/_ingest/pipeline/date_pipeline \
  --header 'authorization: Basic ZWxhc3RpYzpwYXNzd29yZA==' \
  --header 'content-type: application/json' \
  --data '{
  "description": "Pipeline for parsing date",
  "processors": [
    {
      "date": {
        "field": "createdTime",
        "formats": [
         "8YYYY-ww"
        ]
      }
    }
  ]
}'
```

